using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver
var options = new JsonSerializerOptions { WriteIndented = true };

// ─── 1. Get strongly-typed JsonTypeInfo<T> ───────────────────────────────────
// GetTypeInfo<T>() is the generic convenience that returns JsonTypeInfo<T> directly.
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got JsonTypeInfo<Person>: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Ada", 38), personInfo);
Console.WriteLine(json);

// ─── 2. Probe without throwing (TryGetTypeInfo) ──────────────────────────────
// TryGetTypeInfo returns false instead of throwing when metadata isn't available.
// With the default reflection resolver every type succeeds, so we use a
// source-gen-only options instance to show the "not available" path.

var restrictedOptions = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver
    {
        Modifiers =
        {
            // Strip out everything except Person
            info => { if (info.Type != typeof(Person)) info.Properties.Clear(); }
        }
    }
};

if (restrictedOptions.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? found))
    Console.WriteLine($"\n✓ Metadata available for Person: {found!.Type.Name}");
else
    Console.WriteLine("\n✗ No metadata for Person");

// UnknownWidget – show that TryGetTypeInfo returns false for unknown types
// when the resolver returns null.
var emptyResolver = new JsonSerializerOptions
{
    TypeInfoResolver = JsonTypeInfoResolver.Combine() // resolver that resolves nothing
};

if (emptyResolver.TryGetTypeInfo(typeof(UnknownWidget), out _))
    Console.WriteLine("✓ Metadata available for UnknownWidget");
else
    Console.WriteLine("✗ No metadata for UnknownWidget (no exception thrown!)");

// ─── Types ───────────────────────────────────────────────────────────────────
record Person(string Name, int Age);
record UnknownWidget(int Id);

